import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Login = ({ setIsLoggedIn, setUserRole }) => {
  const [role, setRole] = useState('cliente');
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    
    // 1. Guardamos en Storage
    localStorage.setItem('token-falso', 'token-123');
    localStorage.setItem('user-role', role);
    
    // 2. Actualizamos App.js (ESTO DISPARA EL RE-RENDER DE LAS RUTAS)
    setIsLoggedIn(true);
    setUserRole(role);
    
    // 3. Navegamos
    if (role === 'vendedor') {
      navigate('/dashboard');
    } else {
      navigate('/');
    }
  };

  return (
    <div style={containerStyle}>
      <form onSubmit={handleLogin} style={formStyle}>
        <h2 style={{ textAlign: 'center', marginBottom: '20px' }}>Iniciar Sesión</h2>
        
        <div style={roleSelector}>
          <button 
            type="button" 
            onClick={() => setRole('cliente')}
            style={role === 'cliente' ? activeTab : inactiveTab}
          >Soy Cliente</button>
          <button 
            type="button" 
            onClick={() => setRole('vendedor')}
            style={role === 'vendedor' ? activeTab : inactiveTab}
          >Soy Vendedor</button>
        </div>

        <input type="email" placeholder="Correo electrónico" style={inputStyle} required />
        <input type="password" placeholder="Contraseña" style={inputStyle} required />
        
        <button type="submit" style={btnSubmit}>
          Entrar como {role === 'cliente' ? 'Cliente' : 'Comercio'}
        </button>
      </form>
    </div>
  );
};

const containerStyle = { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' };
const formStyle = { background: 'white', padding: '40px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '350px' };
const roleSelector = { display: 'flex', gap: '10px', marginBottom: '20px', background: '#f1f5f9', padding: '5px', borderRadius: '12px' };
const activeTab = { flex: 1, padding: '10px', border: 'none', borderRadius: '8px', background: '#e67e22', color: 'white', fontWeight: 'bold', cursor: 'pointer' };
const inactiveTab = { flex: 1, padding: '10px', border: 'none', borderRadius: '8px', background: 'transparent', color: '#64748b', cursor: 'pointer' };
const inputStyle = { width: '100%', padding: '12px', marginBottom: '15px', borderRadius: '10px', border: '1px solid #ddd', boxSizing: 'border-box' };
const btnSubmit = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };

export default Login;
